<span class="line"><span style="color:#61AFEF;">newman</span><span style="color:#98C379;"> run</span><span style="color:#98C379;"> collection.json</span><span style="color:#D19A66;"> -r</span><span style="color:#98C379;"> html,json,junit</span></span>
